import grpc
from concurrent import futures
import logging

from envoy.service.auth.v3 import external_auth_pb2
from envoy.service.auth.v3 import external_auth_pb2_grpc
from envoy.type.v3 import http_status_pb2
from google.rpc import status_pb2, code_pb2

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class AuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, authorized_tokens=None):
        self.authorized_tokens = authorized_tokens or {"valid-token-123", "admin-token-456"}
        self.required_header = "authorization"
        
    def Check(self, request, context):
        logger.info("Received CheckRequest")
        
        http_request = request.attributes.request.http
        headers = http_request.headers
        path = http_request.path
        method = http_request.method
        
        logger.info(f"Method: {method}, Path: {path}")
        logger.info(f"Headers: {dict(headers)}")
        
        auth_header = headers.get(self.required_header, "")
        
        if not auth_header:
            logger.warning("Missing authorization header")
            return self._create_denied_response(
                code_pb2.UNAUTHENTICATED,
                "Missing authorization header",
                401
            )
        
        token = auth_header.replace("Bearer ", "").strip()
        
        if token not in self.authorized_tokens:
            logger.warning(f"Invalid token: {token}")
            return self._create_denied_response(
                code_pb2.PERMISSION_DENIED,
                "Invalid or expired token",
                403
            )
        
        logger.info("Authorization successful")
        return self._create_ok_response(headers, token)
    
    def _create_ok_response(self, original_headers, token):
        response = external_auth_pb2.CheckResponse()
        response.status.code = code_pb2.OK
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-user",
                    value=token
                )
            )
        )
        
        response.ok_response.headers.add(
            header=external_auth_pb2.HeaderValueOption(
                header=external_auth_pb2.HeaderValue(
                    key="x-auth-result",
                    value="authorized"
                )
            )
        )
        
        return response
    
    def _create_denied_response(self, grpc_code, message, http_status):
        response = external_auth_pb2.CheckResponse()
        response.status.code = grpc_code
        response.status.message = message
        
        response.denied_response.status.code = http_status
        
        response.denied_response.headers.add(
            header=external_auth_pb2.HeaderValue(
                key="content-type",
                value="application/json"
            )
        )
        
        response.denied_response.body = f'{{"error": "{message}"}}'
        
        return response


class CustomAuthorizationService(external_auth_pb2_grpc.AuthorizationServicer):
    def __init__(self, custom_auth_function=None):
        self.custom_auth_function = custom_auth_function or self.default_auth_logic
        
    def default_auth_logic(self, headers, path, method):
        api_key = headers.get("x-api-key", "")
        user_id = headers.get("x-user-id", "")
        
        if not api_key:
            return False, "Missing API key", 401
        
        if api_key != "secret-api-key-789":
            return False, "Invalid API key", 403
        
        if path.startswith("/admin") and user_id != "admin":
            return False, "Insufficient permissions", 403
        
        return True, "OK", 200
    
    def Check(self, request, context):
        logger.info("Received CheckRequest (Custom)")
        
        http_request = request.attributes.request.http
        headers = http_request.headers
        path = http_request.path
        method = http_request.method
        host = http_request.host
        
        logger.info(f"Host: {host}, Method: {method}, Path: {path}")
        
        is_authorized, message, status_code = self.custom_auth_function(
            headers, path, method
        )
        
        if is_authorized:
            logger.info("Request authorized")
            response = external_auth_pb2.CheckResponse()
            response.status.code = code_pb2.OK
            
            response.ok_response.headers.add(
                header=external_auth_pb2.HeaderValueOption(
                    header=external_auth_pb2.HeaderValue(
                        key="x-custom-auth",
                        value="passed"
                    )
                )
            )
            
            for key, value in headers.items():
                if key.startswith("x-forward-"):
                    response.ok_response.headers.add(
                        header=external_auth_pb2.HeaderValueOption(
                            header=external_auth_pb2.HeaderValue(
                                key=key,
                                value=value
                            )
                        )
                    )
            
            return response
        else:
            logger.warning(f"Request denied: {message}")
            response = external_auth_pb2.CheckResponse()
            
            if status_code == 401:
                response.status.code = code_pb2.UNAUTHENTICATED
            else:
                response.status.code = code_pb2.PERMISSION_DENIED
            
            response.status.message = message
            response.denied_response.status.code = status_code
            response.denied_response.body = f'{{"error": "{message}", "status": {status_code}}}'
            
            response.denied_response.headers.add(
                header=external_auth_pb2.HeaderValue(
                    key="content-type",
                    value="application/json"
                )
            )
            
            return response


def serve(port=50051, service_type="basic"):
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    if service_type == "custom":
        external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
            CustomAuthorizationService(), server
        )
        logger.info("Starting Custom Authorization Service")
    else:
        external_auth_pb2_grpc.add_AuthorizationServicer_to_server(
            AuthorizationService(), server
        )
        logger.info("Starting Basic Authorization Service")
    
    server.add_insecure_port(f"[::]:{port}")
    server.start()
    logger.info(f"Server started on port {port}")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server")
        server.stop(0)


if __name__ == "__main__":
    import sys
    
    service_type = sys.argv[1] if len(sys.argv) > 1 else "basic"
    port = int(sys.argv[2]) if len(sys.argv) > 2 else 50051
    
    serve(port=port, service_type=service_type)